// ============================================================
// SÉQUENCEUR MEPA V6.2 — 27 WP
// Stratification correcte (Guide Méthodologique §1.3 + Stratification V6.2) :
// LOI PHYSIQUE : I10, C1, C2 | CŒUR : F1-F10 | STRESS : I1-I9, C3-C6, T1
// ============================================================
"use strict";
const MEPA_CONFIG_DIR = $env.MEPA_SCRIPTS_DIR
  ? $env.MEPA_SCRIPTS_DIR.replace('/scripts', '/config')
  : '/data/mepa/config';

const WP_LIST = [{"wp_id": "WP-I10-1", "fiche": "WP-I10-1_Rwanda_v62.json", "phase": "LOI_PHYSIQUE", "zone": "LOI PHYSIQUE"}, {"wp_id": "WP-C1-1", "fiche": "WP-C1-1_Haiti_v62.json", "phase": "LOI_PHYSIQUE", "zone": "LOI PHYSIQUE"}, {"wp_id": "WP-C2-1", "fiche": "WP-C2-1_Egypte2011_v62.json", "phase": "LOI_PHYSIQUE", "zone": "LOI PHYSIQUE"}, {"wp_id": "WP-F1-1", "fiche": "WP-F1-1_RomeIIIe_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F2-1", "fiche": "WP-F2-1_RomeTardive_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F3-1", "fiche": "WP-F3-1_MayaClassique_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F4-1", "fiche": "WP-F4-1_EgypteAncienne_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F5-1", "fiche": "WP-F5-1_VeniseDéclin_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F6-1", "fiche": "WP-F6-1_EmpireOttoman_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F7-1", "fiche": "WP-F7-1_RevolutionHaitienne_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F8-1", "fiche": "WP-F8-1_FranceRevolutionnaire_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F9-1", "fiche": "WP-F9-1_AngleterreStabilite_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-F10-1", "fiche": "WP-F10-1_CommuneParis_v62.json", "phase": "FONDATEURS", "zone": "COEUR DE MODELE"}, {"wp_id": "WP-I1-1", "fiche": "WP-I1-1_AngleterreIndustrielle_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I2-1", "fiche": "WP-I2-1_Russie1917_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I3-1", "fiche": "WP-I3-1_JaponMeijiGuerre_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I4-1", "fiche": "WP-I4-1_AllemagneNazie_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I5-1", "fiche": "WP-I5-1_EspagneGuerreCivile_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I6-1", "fiche": "WP-I6-1_Tiananmen_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I7-1", "fiche": "WP-I7-1_URSS_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I8-1", "fiche": "WP-I8-1_ChineDeng_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-I9-1", "fiche": "WP-I9-1_Singapour_v62.json", "phase": "INDUSTRIALISATION", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-C3-1", "fiche": "WP-C3-1_Argentine_v62.json", "phase": "CRISES", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-C4-1", "fiche": "WP-C4-1_Liban_v62.json", "phase": "CRISES", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-C5-1", "fiche": "WP-C5-1_Iran_v62.json", "phase": "CRISES", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-C6-1", "fiche": "WP-C6-1_ChineXi_v62.json", "phase": "CRISES", "zone": "ZONE DE STRESS"}, {"wp_id": "WP-T1-1", "fiche": "WP-T1-1_GuerreSecession_v62.json", "phase": "TRANSITIONS", "zone": "ZONE DE STRESS"}];

return WP_LIST.map((wp, idx) => ({
  json: {
    seq_index:           idx + 1,
    seq_total:           WP_LIST.length,
    wp_id:               wp.wp_id,
    fiche_path:          `${MEPA_CONFIG_DIR}/v6.2/${wp.fiche}`,
    phase:               wp.phase,
    zone_stratification: wp.zone,
    seq_started_at:      new Date().toISOString()
  }
}));

// ============================================================
// SÉQUENCEUR — Log + triage (v4)
// Lit le passeport depuis le fichier disque — source canonique.
// Indépendant de l'output de Execute Workflow.
// ============================================================
"use strict";
const fs   = require('fs');
const data = $input.item.json;

const BASE = $env.MEPA_OUTPUT_DIR || '/data/mepa/outputs';

// wp_id est toujours présent (propagé depuis Init via Execute Workflow)
const wp_id = data?.wp_id || '?';

// ── Lire le passeport depuis le fichier ──────────────────────────────────
let passeport = {};
let passeport_error = null;
try {
  const p = `${BASE}/passeports/${wp_id}_passeport.json`;
  passeport = JSON.parse(fs.readFileSync(p, 'utf8'));
} catch(e) {
  passeport_error = e.message;
}

// Lire le compact s'il existe
let compact = {};
try {
  const c = `${BASE}/certification/${wp_id}_passeport_compact.json`;
  compact = JSON.parse(fs.readFileSync(c, 'utf8'));
} catch(_) {}

// ── Extraire les champs clés ─────────────────────────────────────────────
const statut = compact?.statut_cert
            || passeport?.statut_global?.code
            || passeport?.statut_cert
            || data?.statut_certification
            || 'INCONNU';

const cci        = compact?.CCI
                ?? passeport?.cci_global
                ?? data?.cci_global
                ?? null;

const robustesse  = compact?.robustesse
                 || passeport?.robustesse_n1
                 || data?.robustesse_n1
                 || null;

const concordance = compact?.concordant
                 ?? passeport?.concordance
                 ?? null;

const traj_diagn  = compact?.traj_diagn
                 || passeport?.traj_diagn
                 || null;

const traj_att    = compact?.traj_attendue
                 || passeport?.traj_attendue
                 || null;

// ── Détecter cas fatals ──────────────────────────────────────────────────
const passeport_absent = Boolean(passeport_error);
const is_nc = data?.statut_nc === 'DONNÉES_INSUFFISANTES'
           || statut === 'NC_BLOQUANT';
const is_runner_error = !passeport_absent
  ? false
  : ((data?.exitCode != null && data?.exitCode !== 0)
     || data?.status === 'RUNNER_ERROR'
     || data?.status === 'ERREUR_FATALE');
const is_fatal = Boolean(is_nc || (is_runner_error && passeport_absent));

const entry = {
  seq_index:     data?.seq_index ?? null,
  wp_id,
  phase:         data?.phase || '?',
  statut_cert:   statut,
  cci,
  robustesse,
  concordance,
  traj_diagn,
  traj_attendue: traj_att,
  passeport_absent,
  passeport_error: passeport_error || null,
  is_fatal,
  timestamp:     new Date().toISOString()
};

return {
  json: {
    log_entry:    entry,
    is_fatal,
    wp_id,
    statut_cert:  statut,
    cci,
    seq_progress: `${data?.seq_index ?? '?'}/${data?.seq_total ?? 3}`,
    message:      `[SEQ ${data?.seq_index ?? '?'}] ${wp_id} → ${statut} | CCI:${cci ?? 'n/a'} | passeport:${passeport_absent ? 'ABSENT' : 'OK'}`
  }
};

// ============================================================
// SÉQUENCEUR — Alerte fatale (NC bloquant ou erreur runner)
// Écrit dans outputs/sequencer_alerts.json et s'arrête.
// ============================================================
"use strict";
const fs = require('fs');
const data = $input.item.json;
const BASE  = $env.MEPA_OUTPUT_DIR || '/data/mepa/outputs';
const ALERT_PATH = `${BASE}/sequencer_alerts.json`;

let alerts = [];
try { alerts = JSON.parse(fs.readFileSync(ALERT_PATH, 'utf8')); } catch(_) {}

alerts.push({
  wp_id:     data.wp_id || '?',
  motif:     data.motif || data.status || 'ERREUR_FATALE',
  detail:    data.message || data.action_requise || '',
  timestamp: new Date().toISOString()
});
fs.writeFileSync(ALERT_PATH, JSON.stringify(alerts, null, 2), 'utf8');

// Lancer une erreur pour arrêter le workflow n8n
throw new Error(`[SÉQUENCEUR STOP] ${data.wp_id} — ${data.motif || 'ERREUR_FATALE'}. Voir ${ALERT_PATH}`);

// ============================================================
// SÉQUENCEUR — Synthèse Finale (v4)
// Lit TOUS les passeports depuis le disque — indépendant
// du nombre d'items reçus de Execute Workflow.
// ============================================================
"use strict";
const fs   = require('fs');
const path = require('path');
const BASE = $env.MEPA_OUTPUT_DIR || '/data/mepa/outputs';
const PASS_DIR = `${BASE}/passeports`;
const CERT_DIR = `${BASE}/certification`;
const LOG_PATH = `${BASE}/multipass_log.json`;

// ── Lire tous les passeports disponibles sur disque ──────────────────────
let files = [];
try { files = fs.readdirSync(PASS_DIR).filter(f => f.endsWith('_passeport.json')); }
catch(e) { files = []; }

const log = files.map(file => {
  const wp_id = file.replace('_passeport.json', '');
  let p = {}, compact = {};
  try { p       = JSON.parse(fs.readFileSync(`${PASS_DIR}/${file}`, 'utf8')); } catch(_) {}
  try { compact = JSON.parse(fs.readFileSync(`${CERT_DIR}/${wp_id}_passeport_compact.json`, 'utf8')); } catch(_) {}

  const statut = compact?.statut_cert
              || p?.statut_global?.code
              || p?.statut_cert
              || 'INCONNU';
  const cci    = compact?.CCI ?? p?.cci_global ?? null;

  return {
    wp_id,
    statut_cert:  statut,
    cci,
    robustesse:   compact?.robustesse   || p?.robustesse_n1  || null,
    concordance:  compact?.concordant   ?? p?.concordance    ?? null,
    traj_diagn:   compact?.traj_diagn   || p?.traj_diagn     || null,
    traj_attendue:compact?.traj_attendue|| p?.traj_attendue  || null,
    is_fatal:     false,
    timestamp:    new Date().toISOString()
  };
});

// ── Agréger ──────────────────────────────────────────────────────────────
const total         = log.length;
const certifies     = log.filter(e => e.statut_cert === 'WP_CERTIFIE').length;
const exploratoires = log.filter(e => e.statut_cert === 'WP_EXPLORATOIRE').length;
const inconnus      = log.filter(e => e.statut_cert === 'INCONNU').length;
const cci_vals      = log.filter(e => e.cci != null).map(e => e.cci);
const cci_moyen     = cci_vals.length
  ? parseFloat((cci_vals.reduce((a,b)=>a+b,0)/cci_vals.length).toFixed(3))
  : null;

const synthese = {
  generated_at: new Date().toISOString(),
  corpus: { total, certifies, exploratoires, inconnus },
  cci_moyen,
  detail: log
};

fs.writeFileSync(LOG_PATH, JSON.stringify(synthese, null, 2), 'utf8');

return [{
  json: {
    status:   'SEQUENCEUR_TERMINE',
    corpus:   synthese.corpus,
    cci_moyen,
    log_path: LOG_PATH,
    message:  `[SEQUENCEUR COMPLET] ${total} WP - ${certifies} certifies, ${exploratoires} exploratoires, ${inconnus} inconnus`
  }
}];
